"use strict";(self.webpackChunkinvictus_integration=self.webpackChunkinvictus_integration||[]).push([["1924"],{5226(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"v6.0.0","label":"v6.x","banner":null,"badge":false,"noIndex":false,"className":"docs-version-v6.0.0","isLast":true,"docsSidebars":{"business_users":[{"type":"link","href":"/","label":"Welcome","docId":"index","unlisted":false},{"type":"category","label":"Dashboard","items":[{"type":"category","label":"Your flows","items":[{"type":"link","href":"/dashboard/flows/add","label":"Add new flows","docId":"dashboard/flows/add","unlisted":false},{"type":"link","href":"/dashboard/flows/search","label":"Search for flow traces","docId":"dashboard/flows/search","unlisted":false}],"collapsed":false,"collapsible":false,"href":"/dashboard/flows/"},{"type":"category","label":"Security","items":[{"type":"link","href":"/dashboard/security/users","label":"Add new users","docId":"dashboard/security/users","unlisted":false},{"type":"link","href":"/dashboard/security/roles","label":"Access to flows","docId":"dashboard/security/roles","unlisted":false},{"type":"link","href":"/dashboard/security/auditing","label":"View audits","docId":"dashboard/security/auditing","unlisted":false}],"collapsed":false,"collapsible":false},{"type":"link","href":"/dashboard/settings","label":"Customize Dashboard","docId":"dashboard/settings","unlisted":false}],"collapsed":false,"collapsible":false}],"technical_users":[{"type":"link","href":"/technical","label":"Welcome","docId":"technical","unlisted":false},{"type":"link","href":"/architecture-diagram","label":"Architecture","docId":"architecture-diagram","unlisted":false},{"type":"category","label":"Dashboard","collapsed":true,"collapsible":true,"items":[{"type":"category","label":"Installation","collapsed":true,"collapsible":true,"items":[{"type":"link","href":"/dashboard/installation/give_ad_access","label":"Give access to your Microsoft Entra ID","docId":"dashboard/installation/give_ad_access","unlisted":false},{"type":"link","href":"/dashboard/installation/give_la_access","label":"Give access to your Logic Apps","docId":"dashboard/installation/give_la_access","unlisted":false}],"href":"/dashboard/installation/"},{"type":"category","label":"Import flow traces","items":[{"type":"link","href":"/dashboard/flows/import-flow-traces/import flow-via-fa","label":"Import flow traces via Azure Function Apps","docId":"dashboard/flows/import-flow-traces/import flow-via-fa","unlisted":false},{"type":"link","href":"/dashboard/flows/import-flow-traces/import-flow-prog-via-eh","label":"Import flow traces programmatically via Azure Event Hubs","docId":"dashboard/flows/import-flow-traces/import-flow-prog-via-eh","unlisted":false},{"type":"link","href":"/dashboard/flows/import-flow-traces/import-flow-prog-via-http","label":"Import flow traces programmatically via HTTP","docId":"dashboard/flows/import-flow-traces/import-flow-prog-via-http","unlisted":false},{"type":"link","href":"/dashboard/flows/import-flow-traces/import-flow-via-df","label":"Import flow traces via Azure Data Factory pipelines","docId":"dashboard/flows/import-flow-traces/import-flow-via-df","unlisted":false},{"type":"link","href":"/dashboard/flows/import-flow-traces/import-flows-via-la","label":"Import flow traces via Azure Logic App workflows","docId":"dashboard/flows/import-flow-traces/import-flows-via-la","unlisted":false}],"collapsed":false,"collapsible":false}]},{"type":"category","label":"Framework","collapsed":true,"collapsible":true,"items":[{"type":"link","href":"/framework/installation/","label":"Installation","docId":"framework/installation/index","unlisted":false},{"type":"link","href":"/framework/deprecated/","label":"Deprecated components","docId":"framework/deprecated/index","unlisted":false},{"type":"link","href":"/framework/exceptionHandler","label":"Exception Handler","docId":"framework/exceptionHandler","unlisted":false},{"type":"link","href":"/framework/pubsubV2","label":"PubSub","docId":"framework/pubsubV2","unlisted":false},{"type":"link","href":"/framework/regextranslation","label":"Regex Translator","docId":"framework/regextranslation","unlisted":false},{"type":"link","href":"/framework/sequencecontroller","label":"Sequence Controller","docId":"framework/sequencecontroller","unlisted":false},{"type":"link","href":"/framework/timesequencer","label":"Time Sequencer","docId":"framework/timesequencer","unlisted":false},{"type":"link","href":"/framework/transcoV2","label":"Transco","docId":"framework/transcoV2","unlisted":false},{"type":"link","href":"/framework/xmljsonconverter","label":"XML/JSON Converter","docId":"framework/xmljsonconverter","unlisted":false},{"type":"link","href":"/framework/xsd-validator","label":"XSD Validator","docId":"framework/xsd-validator","unlisted":false}]},{"type":"category","label":"Support","collapsed":true,"collapsible":true,"items":[{"type":"link","href":"/support/migrate-v4-to-v5","label":"Migrate from v4.x to v5","docId":"support/migrate-v4-to-v5","unlisted":false},{"type":"link","href":"/support/migrate-v5-to-v6","label":"Migrate from v5.x to v6","docId":"support/migrate-v5-to-v6","unlisted":false}]}]},"docs":{"architecture-diagram":{"id":"architecture-diagram","title":"Invictus for Azure architecture","description":"An Invictus installation consists of two major parts: the Dashboard and the Framework.","sidebar":"technical_users"},"dashboard/flows/add":{"id":"dashboard/flows/add","title":"Add new flows <OnlyFolderAdminsBadge/>","description":"Each folder can hold one or more \'flows\'. These are message chains, an aggregation of all the messages that can be linked to the same incoming message. Flows are the functional representation of the message with an optional context property name and / or optional context property value.","sidebar":"business_users"},"dashboard/flows/import-flow-traces/import flow-via-fa":{"id":"dashboard/flows/import-flow-traces/import flow-via-fa","title":"Import flow traces via Azure Function App logs <NewSinceBadge version=\\"v6.2\\" />","description":"Invictus allows developers to import flow traces via application logs coming from Azure Function Apps. These logs translate to the startup of the Function App, but can also contain developer-custom logging. Combined, they result in an execution tree in the Dashboard that represents.","sidebar":"technical_users"},"dashboard/flows/import-flow-traces/import-flow-prog-via-eh":{"id":"dashboard/flows/import-flow-traces/import-flow-prog-via-eh","title":"Import flow traces programmatically via Azure Event Hubs","description":"Invictus allows developers to programmatically import flow traces via an Event Hub. This resource can be located by the following:","sidebar":"technical_users"},"dashboard/flows/import-flow-traces/import-flow-prog-via-http":{"id":"dashboard/flows/import-flow-traces/import-flow-prog-via-http","title":"Import flow traces programmatically via HTTP","description":"Invictus allows developers to programmatically import flow traces via a HTTP endpoint. This resource can be located by the following name format:","sidebar":"technical_users"},"dashboard/flows/import-flow-traces/import-flow-via-df":{"id":"dashboard/flows/import-flow-traces/import-flow-via-df","title":"Import flow traces via Azure Data Factory pipelines","description":"For the Invictus Dashboard to know if messages went through your Azure Data Factory pipelines correctly or not, diagnostic settings need to be configured on all pipelines you want to include. These settings should stream their diagnostic traces to the Invictus Event Hubs resource:","sidebar":"technical_users"},"dashboard/flows/import-flow-traces/import-flows-via-la":{"id":"dashboard/flows/import-flow-traces/import-flows-via-la","title":"Import flow traces via Azure Logic App workflows","description":"Invictus is fully supported to import flows from Azure Logic Apps. It allows to keep track of the execution tree of the ran workflows, plus with tracked properties you can trace specific data for your needs besides the general diagnostic settings.","sidebar":"technical_users"},"dashboard/flows/import-flow-traces/index":{"id":"dashboard/flows/import-flow-traces/index","title":"Import flow traces from external sources","description":"Invictus allows \'flow traces\' to be imported from various different sources (Azure Logic App workflows, Azure Data Factory, HTTP...). Via diagnostic information, these traces are collected in Invictus\' backend storage and so that the current status of the \'flow\' can be shown in the Dashboard."},"dashboard/flows/index":{"id":"dashboard/flows/index","title":"Dashboard Homepage: overview of flow statuses","description":"The Dashboard home page shows you an overview of the current status of all your flows (= message chain). Flows are an aggregation of all diagnostic traces that can be linked to the same incoming message. Besides predefined properties, it can have optional custom properties to give context to the user.","sidebar":"business_users"},"dashboard/flows/search":{"id":"dashboard/flows/search","title":"Search for flow traces","description":"logo","sidebar":"business_users"},"dashboard/installation/give_ad_access":{"id":"dashboard/installation/give_ad_access","title":"Give Invictus access to your Microsoft Entra ID","description":"To use your Microsoft Entra ID groups as a way of authentication and flow authorization, you need to follow these steps.","sidebar":"technical_users"},"dashboard/installation/give_la_access":{"id":"dashboard/installation/give_la_access","title":"Give Invictus access to your Azure Logic Apps","description":"When running Workflow operations like resubmit, resume; Invictus needs access to your Azure Logic Apps resources. Please set the Logic App Contributor, Logic Apps Standard Contributor and Website Contributor rights for the Azure Container Apps Managed Identity and Flow Handler Azure Container App on the resource group where your Azure Logic Apps are located.","sidebar":"technical_users"},"dashboard/installation/index":{"id":"dashboard/installation/index","title":"Installing Invictus Dashboard","description":"To access the resources stored on Azure Storage and Azure Container Registry you have to request an SAS-token and ACR Password from coditproducts@codit.eu.","sidebar":"technical_users"},"dashboard/security/auditing":{"id":"dashboard/security/auditing","title":"View audited actions <OnlyAdminsBadge/>","description":"logo","sidebar":"business_users"},"dashboard/security/roles":{"id":"dashboard/security/roles","title":"Control the access to your flows","description":"Available flow permissions","sidebar":"business_users"},"dashboard/security/users":{"id":"dashboard/security/users","title":"Manage Users in the Dashboard","description":"logo","sidebar":"business_users"},"dashboard/settings":{"id":"dashboard/settings","title":"Customize the Dashboard to your needs","description":"logo","sidebar":"business_users"},"framework/deprecated/index":{"id":"framework/deprecated/index","title":"Deprecated Framework components","description":"The following listed components are considered deprecated Invictus Framework components and will stop receiving support.","sidebar":"technical_users"},"framework/deprecated/matrix":{"id":"framework/deprecated/matrix","title":"Matrix","description":"## \u26A0\uFE0F Attention"},"framework/deprecated/matrix-basic":{"id":"framework/deprecated/matrix-basic","title":"Matrix - Basic Promotion","description":"## \u26A0\uFE0F Attention"},"framework/deprecated/matrix-promote":{"id":"framework/deprecated/matrix-promote","title":"Matrix - Promotion","description":"## \u26A0\uFE0F Attention"},"framework/deprecated/pubsub":{"id":"framework/deprecated/pubsub","title":"Publish / Subscribe","description":"## \u26A0\uFE0F Attention"},"framework/deprecated/transco":{"id":"framework/deprecated/transco","title":"Transco","description":"## \u26A0\uFE0F Attention"},"framework/deprecated/transco-assemblies":{"id":"framework/deprecated/transco-assemblies","title":"Transco - Custom Assemblies","description":"## \u26A0\uFE0F Attention"},"framework/deprecated/transco-extraction":{"id":"framework/deprecated/transco-extraction","title":"Transco - Extraction","description":"## \u26A0\uFE0F Attention"},"framework/exceptionHandler":{"id":"framework/exceptionHandler","title":"Explain Logic App workflows failures with the <u>Exception Handler</u>","description":"Most who have worked with Logic Apps is familiar with the error An action failed. No dependent actions succeeded. This is a generic error that offers no clear information on what went wrong.","sidebar":"technical_users"},"framework/installation/index":{"id":"framework/installation/index","title":"Installing Invictus Framework","description":"To access the resources stored on Azure Storage and Azure Container Registry you have to request an SAS-token and Azure Container Registry password from coditproducts@codit.eu.","sidebar":"technical_users"},"framework/pubsubV2":{"id":"framework/pubsubV2","title":"Run Logic App workflows as publisher/subscriber with the <u>PubSub</u>","description":"Asynchronous messaging helps with decoupling publishers from consumers, as it avoids the blocking during publishing. Especially in Azure Logic Apps workflows, where we can\'t assume that the interaction between publisher and consumer is always synchronous.","sidebar":"technical_users"},"framework/regextranslation":{"id":"framework/regextranslation","title":"Replace user content in Logic App workflows with the <u>Regex Translator</u>","description":"At the time of writing, there is no built-in Logic App functionality available to run regular expression replacements without using inline code. The Invictus Regex Translation Framework component fills this missing link. It provides a HTTP-endpoint to run regular expression replacements. All available translations are available in an Azure Table Storage.","sidebar":"technical_users"},"framework/sequencecontroller":{"id":"framework/sequencecontroller","title":"Run Logic App workflows in sequence by indexing with the <u>Sequence Controller</u>","description":"Some dependent external systems can\'t handle parallel message processing or requires a certain order of messages. Sending messages serially (for example, by setting the concurrency on a Logic App to 1) can be a solution, at the cost of a big performance impact.","sidebar":"technical_users"},"framework/timesequencer":{"id":"framework/timesequencer","title":"Run Logic App workflows in sequence by timestamps with the <u>Time Sequencer</u>","description":"At the time of writing, there is no built-in way in Azure Logic Apps to \'control\' the sequence in which workflow runs are executing. In certain scenarios, even though a  workflow triggers before another, you want the first one to wait for the second. A common example is entity updates, where you don\'t want older updates to override newer ones - even though the workflow with the older updates \'happened after\' the newer ones.","sidebar":"technical_users"},"framework/transcoV2":{"id":"framework/transcoV2","title":"Promote user content from SQL in Logic App workflows with <u>Transco</u>","description":"Integration scenarios often need to \'promote\' or \'enrich\' messages/data from external stored systems. Codit is a long-term implementer of something called \'Transco\', which was originally a Microsoft BizTalk component. Now, modern Azure Logic Apps integration benefits from this behavior.","sidebar":"technical_users"},"framework/xmljsonconverter":{"id":"framework/xmljsonconverter","title":"Convert between XML/JSON in Logic Apps workflows with the <u>XML-JSON Converter</u>","description":"To run simple XML/JSON transformations, the built-in Logic Apps expressions json and xml do the job fine. When using custom mapping, selection, or structures, the built-in expressions might be too complex to set up.","sidebar":"technical_users"},"framework/xsd-validator":{"id":"framework/xsd-validator","title":"Validate XML user content in Logic App workflows with <u>XSD Validator</u>","description":"When processing XML files in Logic App workflows, XSD validation is a necessary pre-processing step to catch errors beforehand. Microsoft currently only supports XSD validation within Logic App workflows on top of Azure Integration Accounts. This kind of resource is rather expensive and not always available within the cost boundaries of client projects.","sidebar":"technical_users"},"index":{"id":"index","title":"","description":"Better control and overview your integrations with the Invictus, designed by Codit","sidebar":"business_users"},"support/migrate-v4-to-v5":{"id":"support/migrate-v4-to-v5","title":"Migrate from v4.x to Invictus v5","description":"Preparing environment","sidebar":"technical_users"},"support/migrate-v5-to-v6":{"id":"support/migrate-v5-to-v6","title":"Migrate from v5.x to Invictus v6","description":"Invictus v6 uses containerized API instead of Web API or Azure Functions. This means that the endpoints for the Dashboard and the Framework components changes.","sidebar":"technical_users"},"technical":{"id":"technical","title":"Introduction","description":"Invictus logo","sidebar":"technical_users"}}}}')}}]);